```python
# solution.py

class Task:
    def __init__(self, task_id, description, assigned_to, due_date, status='Pending'):
        self.task_id = task_id
        self.description = description
        self.assigned_to = assigned_to
        self.due_date = due_date
        self.status = status

    def update_status(self, new_status):
        self.status = new_status

    def __str__(self):
        return f"Task ID: {self.task_id}, Description: {self.description}, Assigned To: {self.assigned_to}, Due Date: {self.due_date}, Status: {self.status}"

class Resource:
    def __init__(self, resource_id, name, availability):
        self.resource_id = resource_id
        self.name = name
        self.availability = availability

    def update_availability(self, new_availability):
        self.availability = new_availability

    def __str__(self):
        return f"Resource ID: {self.resource_id}, Name: {self.name}, Availability: {self.availability}"

class Communication:
    def __init__(self):
        self.messages = []

    def send_message(self, sender, recipient, message):
        self.messages.append((sender, recipient, message))

    def get_messages(self, recipient):
        return [msg for msg in self.messages if msg[1] == recipient]

class TeamSyncPro:
    def __init__(self):
        self.tasks = []
        self.resources = []
        self.communication = Communication()

    def add_task(self, task):
        self.tasks.append(task)

    def get_task(self, task_id):
        for task in self.tasks:
            if task.task_id == task_id:
                return task
        return None

    def add_resource(self, resource):
        self.resources.append(resource)

    def get_resource(self, resource_id):
        for resource in self.resources:
            if resource.resource_id == resource_id:
                return resource
        return None

    def send_communication(self, sender, recipient, message):
        self.communication.send_message(sender, recipient, message)

    def get_communications(self, recipient):
        return self.communication.get_messages(recipient)

# Example usage
if __name__ == "__main__":
    team_sync_pro = TeamSyncPro()

    # Adding tasks
    task1 = Task(task_id=1, description="Design UI", assigned_to="Alice", due_date="2023-10-01")
    task2 = Task(task_id=2, description="Develop Backend", assigned_to="Bob", due_date="2023-10-15")
    team_sync_pro.add_task(task1)
    team_sync_pro.add_task(task2)

    # Adding resources
    resource1 = Resource(resource_id=1, name="Alice", availability="Available")
    resource2 = Resource(resource_id=2, name="Bob", availability="Available")
    team_sync_pro.add_resource(resource1)
    team_sync_pro.add_resource(resource2)

    # Sending communication
    team_sync_pro.send_communication(sender="Alice", recipient="Bob", message="UI design is ready for review.")

    # Retrieving and displaying tasks, resources, and communications
    print(team_sync_pro.get_task(1))
    print(team_sync_pro.get_resource(2))
    print(team_sync_pro.get_communications("Bob"))
```

